/**
 * Analytics service — aggregates order and user data into dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user counts
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricDetailResponse,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeGranularity,
  TimeSeriesPoint,
  TimeSeriesQuery,
  TimeSeriesResponse,
  TopProduct,
  TopProductsResponse,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Full dashboard summary — powers GET /api/analytics/dashboard.
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info(`Generating dashboard for ${query.startDate} to ${query.endDate}`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const durationMs = end.getTime() - start.getTime();
    const prevStart = new Date(start.getTime() - durationMs);
    const prevEnd = new Date(start.getTime());

    const orders = this.getOrdersInRange(start, end, query.userId);
    const prevOrders = this.getOrdersInRange(prevStart, prevEnd, query.userId);
    const users = this.getUsersInRange(start, end);
    const prevUsers = this.getUsersInRange(prevStart, prevEnd);

    const totalOrders = orders.length;
    const prevTotalOrders = prevOrders.length;
    const totalRevenue = this.sumRevenue(orders);
    const prevTotalRevenue = this.sumRevenue(prevOrders);
    const totalUsers = users.length;
    const prevTotalUsers = prevUsers.length;
    const aov = totalOrders > 0 ? totalRevenue / totalOrders : 0;
    const prevAov = prevTotalOrders > 0 ? prevTotalRevenue / prevTotalOrders : 0;

    const metrics: MetricSummary[] = [
      this.buildMetricSummary('orders', 'Total Orders', totalOrders, prevTotalOrders),
      this.buildMetricSummary('revenue', 'Total Revenue', totalRevenue, prevTotalRevenue),
      this.buildMetricSummary('users', 'New Users', totalUsers, prevTotalUsers),
      this.buildMetricSummary('average-order-value', 'Avg Order Value', aov, prevAov),
    ];

    const ordersByStatus = this.computeStatusBreakdown(orders);
    const revenueTimeSeries = this.bucketOrderMetric(orders, 'revenue', 'day', start, end);

    return {
      metrics,
      ordersByStatus,
      revenueTimeSeries,
      query,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Single metric detail — powers GET /api/analytics/metrics/:type.
   */
  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricDetailResponse> {
    this.logger.info(`Generating metric detail for ${type}`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const durationMs = end.getTime() - start.getTime();
    const prevStart = new Date(start.getTime() - durationMs);
    const prevEnd = new Date(start.getTime());

    const orders = this.getOrdersInRange(start, end, query.userId);
    const prevOrders = this.getOrdersInRange(prevStart, prevEnd, query.userId);
    const users = this.getUsersInRange(start, end);
    const prevUsers = this.getUsersInRange(prevStart, prevEnd);

    const { value, prevValue } = this.computeMetricValues(type, orders, prevOrders, users, prevUsers);
    const metric = this.buildMetricSummary(type, this.metricLabel(type), value, prevValue);

    const timeSeries = type === 'users'
      ? this.bucketUserMetric(users, 'day', start, end)
      : this.bucketOrderMetric(orders, type, 'day', start, end);

    return {
      metric,
      timeSeries,
      query,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Time series data — powers GET /api/analytics/timeseries.
   */
  async getTimeSeries(query: TimeSeriesQuery): Promise<TimeSeriesResponse> {
    const granularity: TimeGranularity = query.granularity ?? 'day';
    this.logger.info(`Generating time series for ${query.metric} by ${granularity}`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const orders = this.getOrdersInRange(start, end, query.userId);
    const users = this.getUsersInRange(start, end);

    const points = query.metric === 'users'
      ? this.bucketUserMetric(users, granularity, start, end)
      : this.bucketOrderMetric(orders, query.metric, granularity, start, end);

    return {
      metric: query.metric,
      granularity,
      points,
      query,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Top products by revenue — powers GET /api/analytics/top-products.
   */
  async getTopProducts(query: AnalyticsQuery, limit: number = 10): Promise<TopProductsResponse> {
    this.logger.info(`Generating top ${limit} products`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const orders = this.getOrdersInRange(start, end, query.userId);

    const productMap = new Map<string, { name: string; totalQuantity: number; totalRevenue: number }>();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        const itemRevenue = item.quantity * item.unitPrice;
        if (existing) {
          existing.totalQuantity += item.quantity;
          existing.totalRevenue += itemRevenue;
        } else {
          productMap.set(item.productId, {
            name: item.name,
            totalQuantity: item.quantity,
            totalRevenue: itemRevenue,
          });
        }
      }
    }

    const products: TopProduct[] = Array.from(productMap.entries())
      .map(([productId, data]) => ({
        productId,
        name: data.name,
        totalQuantity: data.totalQuantity,
        totalRevenue: data.totalRevenue,
      }))
      .sort((a, b) => b.totalRevenue - a.totalRevenue)
      .slice(0, limit);

    return {
      products,
      query,
      generatedAt: new Date().toISOString(),
    };
  }

  // ---------------------------------------------------------------------------
  // Data access helpers
  // ---------------------------------------------------------------------------

  private getOrdersInRange(start: Date, end: Date, userId?: string): Order[] {
    return this.orderRepository.findAll((order) => {
      const inRange = order.createdAt >= start && order.createdAt <= end;
      return userId ? inRange && order.userId === userId : inRange;
    });
  }

  private getUsersInRange(start: Date, end: Date): User[] {
    return this.userRepository.findAll((user) => {
      return user.createdAt >= start && user.createdAt <= end;
    });
  }

  // ---------------------------------------------------------------------------
  // Aggregation helpers
  // ---------------------------------------------------------------------------

  private sumRevenue(orders: Order[]): number {
    return orders.reduce((sum, o) => sum + o.total, 0);
  }

  private computeMetricValues(
    type: MetricType,
    orders: Order[],
    prevOrders: Order[],
    users: User[],
    prevUsers: User[],
  ): { value: number; prevValue: number } {
    switch (type) {
      case 'orders':
        return { value: orders.length, prevValue: prevOrders.length };
      case 'revenue':
        return { value: this.sumRevenue(orders), prevValue: this.sumRevenue(prevOrders) };
      case 'users':
        return { value: users.length, prevValue: prevUsers.length };
      case 'average-order-value': {
        const aov = orders.length > 0 ? this.sumRevenue(orders) / orders.length : 0;
        const prevAov = prevOrders.length > 0 ? this.sumRevenue(prevOrders) / prevOrders.length : 0;
        return { value: aov, prevValue: prevAov };
      }
    }
  }

  private buildMetricSummary(type: MetricType, label: string, value: number, previousValue: number): MetricSummary {
    let changePercent = 0;
    if (previousValue !== 0) {
      changePercent = ((value - previousValue) / previousValue) * 100;
    }

    let trend: 'up' | 'down' | 'flat' = 'flat';
    if (changePercent > 0) {
      trend = 'up';
    } else if (changePercent < 0) {
      trend = 'down';
    }

    return { type, label, value, previousValue, changePercent, trend };
  }

  private computeStatusBreakdown(orders: Order[]): OrderStatusBreakdown[] {
    const statusCounts = new Map<string, number>();
    const statuses = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
    for (const s of statuses) {
      statusCounts.set(s, 0);
    }

    for (const order of orders) {
      statusCounts.set(order.status, (statusCounts.get(order.status) ?? 0) + 1);
    }

    const total = orders.length;
    return statuses.map((status) => {
      const count = statusCounts.get(status) ?? 0;
      return {
        status,
        count,
        percent: total > 0 ? (count / total) * 100 : 0,
      };
    });
  }

  // ---------------------------------------------------------------------------
  // Time-series bucketing
  // ---------------------------------------------------------------------------

  private bucketOrderMetric(
    orders: Order[],
    metric: MetricType,
    granularity: TimeGranularity,
    start: Date,
    end: Date,
  ): TimeSeriesPoint[] {
    const buckets = this.createBuckets(start, end, granularity);
    const bucketStarts = buckets.map((b) => b.getTime());

    for (const order of orders) {
      const bucketIdx = this.findBucketIndex(order.createdAt.getTime(), bucketStarts);
      if (bucketIdx === -1) continue;

      const key = bucketIdx.toString();
      if (!this.bucketValues.has(key)) {
        this.bucketValues.set(key, { count: 0, revenue: 0 });
      }
      const bucket = this.bucketValues.get(key)!;
      bucket.count += 1;
      bucket.revenue += order.total;
    }

    const points: TimeSeriesPoint[] = buckets.map((bucketDate, idx) => {
      const data = this.bucketValues.get(idx.toString()) ?? { count: 0, revenue: 0 };
      let value: number;
      switch (metric) {
        case 'orders':
          value = data.count;
          break;
        case 'revenue':
          value = data.revenue;
          break;
        case 'average-order-value':
          value = data.count > 0 ? data.revenue / data.count : 0;
          break;
        default:
          value = 0;
      }
      return {
        timestamp: bucketDate.toISOString(),
        value,
        label: this.bucketLabel(bucketDate, granularity),
      };
    });

    this.bucketValues.clear();
    return points;
  }

  private bucketUserMetric(
    users: User[],
    granularity: TimeGranularity,
    start: Date,
    end: Date,
  ): TimeSeriesPoint[] {
    const buckets = this.createBuckets(start, end, granularity);
    const bucketStarts = buckets.map((b) => b.getTime());

    const counts = new Map<number, number>();
    for (const user of users) {
      const bucketIdx = this.findBucketIndex(user.createdAt.getTime(), bucketStarts);
      if (bucketIdx === -1) continue;
      counts.set(bucketIdx, (counts.get(bucketIdx) ?? 0) + 1);
    }

    return buckets.map((bucketDate, idx) => ({
      timestamp: bucketDate.toISOString(),
      value: counts.get(idx) ?? 0,
      label: this.bucketLabel(bucketDate, granularity),
    }));
  }

  private bucketValues = new Map<string, { count: number; revenue: number }>();

  private createBuckets(start: Date, end: Date, granularity: TimeGranularity): Date[] {
    const buckets: Date[] = [];
    const current = new Date(start);

    while (current <= end) {
      buckets.push(new Date(current));
      switch (granularity) {
        case 'hour':
          current.setUTCHours(current.getUTCHours() + 1);
          break;
        case 'day':
          current.setUTCDate(current.getUTCDate() + 1);
          break;
        case 'week':
          current.setUTCDate(current.getUTCDate() + 7);
          break;
        case 'month':
          current.setUTCMonth(current.getUTCMonth() + 1);
          break;
      }
    }

    return buckets;
  }

  private findBucketIndex(timestamp: number, bucketStarts: number[]): number {
    for (let i = bucketStarts.length - 1; i >= 0; i--) {
      if (timestamp >= bucketStarts[i]) {
        return i;
      }
    }
    return -1;
  }

  private bucketLabel(date: Date, granularity: TimeGranularity): string {
    switch (granularity) {
      case 'hour':
        return `${date.getUTCHours().toString().padStart(2, '0')}:00`;
      case 'day':
        return date.toISOString().slice(0, 10);
      case 'week': {
        const weekEnd = new Date(date);
        weekEnd.setUTCDate(weekEnd.getUTCDate() + 6);
        return `${date.toISOString().slice(0, 10)} – ${weekEnd.toISOString().slice(0, 10)}`;
      }
      case 'month':
        return date.toISOString().slice(0, 7);
    }
  }

  private metricLabel(type: MetricType): string {
    const labels: Record<MetricType, string> = {
      orders: 'Total Orders',
      revenue: 'Total Revenue',
      users: 'New Users',
      'average-order-value': 'Avg Order Value',
    };
    return labels[type];
  }
}
